        return revealed ? revealedURI : baseURI;
    }

    function setPaused(bool _state) external onlyOwner {
        paused = _state;
    }

    function setState(State newState) external onlyOwner onlyWhen(State.Paused) {
        currentState = newState;
        emit StateChanged(newState);
    }

