pragma solidity ^0.8.0;

import "@openzeppelin/contracts/token/ERC721/extensions/ERC721URIStorage.sol";
import "@openzeppelin/contracts/access/Ownable.sol";
import "@openzeppelin/contracts/security/ReentrancyGuard.sol";

contract MyNFT is ERC721URIStorage, Ownable, ReentrancyGuard {
    uint256 public constant MAX_SUPPLY = 10000;
    uint256 public constant MINT_LIMIT = 2;
    uint256 public cost = 0.01 ether;
    string private baseURI;
    bool public paused = true;
    bool public revealed = false;
    string private revealedURI;
    mapping(address => uint256) public addressMintedBalance;
    bool public mintingActive = false;

    event NFTMinted(address indexed sender, uint256 tokenId);
    event MetadataRevealed();
    event WhitelistUpdated(address[] addresses);
    event MintingStateChanged(bool newState);

    constructor(string memory _initBaseURI) ERC721("MyNFT", "MNFT") {
        setBaseURI(_initBaseURI);
    }

    function mint(uint256 _mintAmount) external payable {
        require(mintingActive, "Minting is not active");
        require(!paused, "Minting is paused");
        require(_mintAmount > 0 && _mintAmount <= MINT_LIMIT, "Exceeds maximum mint amount per transaction");
        require(totalSupply() + _mintAmount <= MAX_SUPPLY, "Purchase would exceed max supply");
        require(msg.value >= cost * _mintAmount, "Insufficient funds");

        uint256 totalMinted = _mintAmount;
        uint256 currentTotalSupply = totalSupply();

        for (uint256 i = 0; i < _mintAmount; i++) {
            _safeMint(msg.sender, currentTotalSupply + i);
        }

        addressMintedBalance[msg.sender] += totalMinted;

        emit NFTMinted(msg.sender, currentTotalSupply + totalMinted - 1);
    }

    function reveal(string memory _revealedURI) external onlyOwner {
        require(!revealed, "Metadata already revealed");
        revealedURI = _revealedURI;
        revealed = true;
        emit MetadataRevealed();
    }

    function setCost(uint256 _newCost) external onlyOwner {
        cost = _newCost;
    }

    function setBaseURI(string memory _newBaseURI) public onlyOwner {
        baseURI = _newBaseURI;
    }

    function _baseURI() internal view override returns (string memory) {
        return revealed ? revealedURI : baseURI;
    }

    function setPaused(bool _state) external onlyOwner {
        paused = _state;
    }

    function setMintingActive(bool _active) external onlyOwner {
        mintingActive = _active;
        emit MintingStateChanged(_active);
    }

    function updateWhitelist(address[] calldata _addresses) external onlyOwner {
        for (uint256 i = 0; i < _addresses.length; i++) {
            addressMintedBalance[_addresses[i]] = MINT_LIMIT;
        }
        emit WhitelistUpdated(_addresses);
    }

    function withdraw() public onlyOwner nonReentrant {
        payable(owner()).transfer(address(this).balance);
    }
}
